switch {
case gw.status >= 400:
	// Remove gzip headers for error responses when handler is complete
	gw.removeGzipHeaders()
	gz.Reset(io.Discard)
case !gw.shouldCompress:
	// if compression limit not met after all write commands were executed, then the response data is stored in the
	// internal buffer which should now be written to the response writer directly
	gw.Header().Del(headerContentEncoding)
	gw.Header().Del(headerVary)
	// must refer directly to embedded writer since c.Writer gets overridden
	_, _ = gw.ResponseWriter.Write(gw.buffer.Bytes())
	gz.Reset(io.Discard)
case c.Writer.Size() < 0:
	// do not write gzip footer when nothing is written to the response body
	// Note: This is only executed when gw.minLength == 0 (ie always compress)
	gz.Reset(io.Discard)
}

for i := 0; i < len(contentEncodingField); i++ {
	trimmedValue := strings.TrimSpace(contentEncodingField[i])

	if trimmedValue == "" {
		continue
	}

	if trimmedValue != "gzip" {
		// According to RFC 7231, Section 3.1.2.2:
		// https://www.rfc-editor.org/rfc/rfc7231#section-3.1.2.2
		// An origin server MAY respond with a status code of 415 (Unsupported
		// Media Type) if a representation in the request message has a content
		// coding that is not acceptable.
		_ = c.AbortWithError(http.StatusUnsupportedMediaType, ErrUnsupportedContentEncoding)
	}

	r, err := gzip.NewReader(c.Request.Body)
	if err != nil {
		_ = c.AbortWithError(http.StatusBadRequest, err)

		return
	}

	toClose = append(toClose, c.Request.Body)

	c.Request.Body = r
}

if value, ok := att.value.(map[string]interface{}); ok {
	values = value
} else if value, ok := att.value.(*map[string]interface{}); ok {
	values = *value
} else {
	reflectValue := reflect.Indirect(reflect.ValueOf(att.value))
	for reflectValue.Kind() == reflect.Ptr || reflectValue.Kind() == reflect.Interface {
		reflectValue = reflect.Indirect(reflectValue)
	}
	switch reflectValue.Kind() {
	case reflect.Struct:
		if err := att.db.Statement.Parse(att.value); err == nil {
			ignoreZero := len(att.selectFields) == 0
			for _, f := range att.db.Statement.Schema.Fields {
				if f.Readable {
					if v, isZero := f.ValueOf(att.db.Statement.Context, reflectValue); !isZero || !ignoreZero {
						values[f.DBName] = v
					}
				}
			}
		}
	}
}

for _, col := range columns {
	col.SetDataTypeMap(conf.DataTypeMap)
	col.WithNS(conf.FieldJSONTagNS)

	m := col.ToField(conf.FieldNullable, conf.FieldCoverable, conf.FieldSignable, conf.FieldWithDefaultTag)

	if filterField(m, conf.FilterOpts) == nil {
		continue
	}
	if _, ok := col.ColumnType.ColumnType(); ok && !conf.FieldWithTypeTag { // remove type tag if FieldWithTypeTag == false
		m.GORMTag.Remove("type")
	}

	m = modifyField(m, conf.ModifyOpts)
	if ns, ok := db.NamingStrategy.(schema.NamingStrategy); ok {
		ns.SingularTable = true
		m.Name = ns.SchemaName(ns.TablePrefix + m.Name)
	} else if db.NamingStrategy != nil {
		m.Name = db.NamingStrategy.SchemaName(m.Name)
	}

	fields = append(fields, m)
}

switch t := n.(type) {
case *ast.FuncDecl:
	// check base struct and method name is expect
	structMeta := getParamList(t.Recv)
	if len(structMeta) != 1 {
		return
	}
	if structMeta[0].Type != m.BaseStructType {
		return
	}
	// if m.MethodName is null will generate all methods
	if m.MethodName != "" && m.MethodName != t.Name.Name {
		return
	}

	// use ast read bind start package is UNDEFINED ,set it null string
	structMeta[0].Package = ""
	m.Methods = append(m.Methods, &Method{
		Receiver:   structMeta[0],
		MethodName: t.Name.String(),
		Doc:        t.Doc.Text(),
		Body:       getBody(m.currentFile, int(t.Body.Pos()), int(t.Body.End())),
		Params:     getParamList(t.Type.Params),
		Result:     getParamList(t.Type.Results),
	})
}

for idx, relField := range refForeignFields {
	joinFieldName := cases.Title(language.Und, cases.NoLower).String(relation.FieldSchema.Name) + relField.Name

	if _, ok := ownFieldsMap[joinFieldName]; ok {
		if field.Name != relation.FieldSchema.Name {
			joinFieldName = inflection.Singular(field.Name) + relField.Name
		} else {
			joinFieldName += "Reference"
		}
	}

	if len(joinReferences) > idx {
		joinFieldName = cases.Title(language.Und, cases.NoLower).String(joinReferences[idx])
	}

	referFieldsMap[joinFieldName] = relField

	if _, ok := fieldsMap[joinFieldName]; !ok {
		fieldsMap[joinFieldName] = relField
		joinTableFields = append(joinTableFields, reflect.StructField{
			Name:    joinFieldName,
			PkgPath: relField.StructField.PkgPath,
			Type:    relField.StructField.Type,
			Tag: removeSettingFromTag(appendSettingFromTag(relField.StructField.Tag, "primaryKey"),
				"column", "autoincrement", "index", "unique", "uniqueindex"),
		})
	}
}

if c.before != "" { // if defined before callback
			if c.before == "*" && len(sorted) > 0 {
				if curIdx := getRIndex(sorted, c.name); curIdx == -1 {
					sorted = append([]string{c.name}, sorted...)
				}
			} else if sortedIdx := getRIndex(sorted, c.before); sortedIdx != -1 {
				if curIdx := getRIndex(sorted, c.name); curIdx == -1 {
					// if before callback already sorted, append current callback just after it
					sorted = append(sorted[:sortedIdx], append([]string{c.name}, sorted[sortedIdx:]...)...)
				} else if curIdx > sortedIdx {
					return fmt.Errorf("conflicting callback %s with before %s", c.name, c.before)
				}
			} else if idx := getRIndex(names, c.before); idx != -1 {
				// if before callback exists
				cs[idx].after = c.name
			}
		}

if s, ok := query.(string); ok {
	// if it is a number, then treats it as primary key
	if _, err := strconv.Atoi(s); err != nil {
		if s == "" && len(args) == 0 {
			return nil
		}

		if len(args) == 0 || (len(args) > 0 && strings.Contains(s, "?")) {
			// looks like a where condition
			return []clause.Expression{clause.Expr{SQL: s, Vars: args}}
		}

		if len(args) > 0 && strings.Contains(s, "@") {
			// looks like a named query
			return []clause.Expression{clause.NamedExpr{SQL: s, Vars: args}}
		}

		if strings.Contains(strings.TrimSpace(s), " ") {
			// looks like a where condition
			return []clause.Expression{clause.Expr{SQL: s, Vars: args}}
		}

		if len(args) == 1 {
			return []clause.Expression{clause.Eq{Column: s, Value: args[0]}}
		}
	}
}

switch {
case len(foreignFields) == 0:
	reguessOrErr()
	return
case len(relation.primaryKeys) > 0:
	for idx, primaryKey := range relation.primaryKeys {
		if f := primarySchema.LookUpField(primaryKey); f != nil {
			if len(primaryFields) < idx+1 {
				primaryFields = append(primaryFields, f)
			} else if f != primaryFields[idx] {
				reguessOrErr()
				return
			}
		} else {
			reguessOrErr()
			return
		}
	}
case len(primaryFields) == 0:
	if len(foreignFields) == 1 && primarySchema.PrioritizedPrimaryField != nil {
		primaryFields = append(primaryFields, primarySchema.PrioritizedPrimaryField)
	} else if len(primarySchema.PrimaryFields) == len(foreignFields) {
		primaryFields = append(primaryFields, primarySchema.PrimaryFields...)
	} else {
		reguessOrErr()
		return
	}
}

if s, ok := v.(*serializer); ok {
	if s.fieldValue == nil && s.Serializer == nil {
		rv := field.ReflectValueOf(ctx, value)
		if rv.IsValid() && rv.CanSet() {
			rv.Set(reflect.Zero(field.FieldType))
		}
		return nil
	}
	if s.fieldValue != nil {
		err = oldFieldSetter(ctx, value, s.fieldValue)
	} else if err = s.Serializer.Scan(ctx, field, value, s.value); err == nil {
		if sameElemType {
			field.ReflectValueOf(ctx, value).Set(reflect.ValueOf(s.Serializer).Elem())
		} else if sameType {
			field.ReflectValueOf(ctx, value).Set(reflect.ValueOf(s.Serializer))
		}
		si := reflect.New(serializerType)
		si.Elem().Set(serializerValue)
		s.Serializer = si.Interface().(SerializerInterface)
	}
} else {
	err = oldFieldSetter(ctx, value, v)
}

if !db.DryRun && db.Error == nil {
	ok, mode := hasReturning(db, supportReturning)
	if !ok {
		result, err := db.Statement.ConnPool.ExecContext(db.Statement.Context, db.Statement.SQL.String(), db.Statement.Vars...)

		if db.AddError(err) == nil {
			db.RowsAffected, _ = result.RowsAffected()

			if db.Statement.Result != nil {
				db.Statement.Result.Result = result
				db.Statement.Result.RowsAffected = db.RowsAffected
			}
		}

		return
	}

	if rows, err := db.Statement.ConnPool.QueryContext(db.Statement.Context, db.Statement.SQL.String(), db.Statement.Vars...); db.AddError(err) == nil {
		gorm.Scan(rows, db, mode)

		if db.Statement.Result != nil {
			db.Statement.Result.RowsAffected = db.RowsAffected
		}
		db.AddError(rows.Close())
	}
}

if !db.DryRun && db.Error == nil {
	if ok, mode := hasReturning(db, supportReturning); ok {
		if rows, err := db.Statement.ConnPool.QueryContext(db.Statement.Context, db.Statement.SQL.String(), db.Statement.Vars...); db.AddError(err) == nil {
			dest := db.Statement.Dest
			db.Statement.Dest = db.Statement.ReflectValue.Addr().Interface()
			gorm.Scan(rows, db, mode)
			db.Statement.Dest = dest
			db.AddError(rows.Close())

			if db.Statement.Result != nil {
				db.Statement.Result.RowsAffected = db.RowsAffected
			}
		}
	} else {
		result, err := db.Statement.ConnPool.ExecContext(db.Statement.Context, db.Statement.SQL.String(), db.Statement.Vars...)

		if db.AddError(err) == nil {
			db.RowsAffected, _ = result.RowsAffected()
		}

		if db.Statement.Result != nil {
			db.Statement.Result.Result = result
			db.Statement.Result.RowsAffected = db.RowsAffected
		}
	}
}

switch op.Type {
case clause.OpUnlink, clause.OpDelete:
	joinDB = joinDB.Where("EXISTS (?)", ownersExists)
	if len(op.Conditions) > 0 {
		joinDB = joinDB.Where("EXISTS (?)", relatedExists)
	}
	return joinDB.Delete(nil).Error
case clause.OpUpdate:
	// Update related table rows that have join rows matching owners
	relatedDB := base.Session(&Session{NewDB: true, Context: ctx}).Table(rel.FieldSchema.Table).Where(op.Conditions)

	// correlated join subquery: join.rel_fk = related.pk AND EXISTS owners
	joinSub := base.Session(&Session{NewDB: true, Context: ctx}).Table(rel.JoinTable.Table).Select("1")
	for _, ref := range rel.References {
		if !ref.OwnPrimaryKey && ref.PrimaryKey != nil {
			joinSub = joinSub.Where(clause.Eq{
				Column: clause.Column{Table: rel.JoinTable.Table, Name: ref.ForeignKey.DBName},
				Value:  clause.Column{Table: rel.FieldSchema.Table, Name: ref.PrimaryKey.DBName},
			})
		}
	}
	joinSub = joinSub.Where("EXISTS (?)", ownersExists)
	return relatedDB.Where("EXISTS (?)", joinSub).Updates(setMap).Error
}

switch association.Relationship.Type {
case schema.HasMany:
	for _, ref := range association.Relationship.References {
		key := reflect.ValueOf(ref.ForeignKey.DBName)
		if ref.OwnPrimaryKey {
			v := ref.PrimaryKey.ReflectValueOf(association.DB.Statement.Context, source)
			mapv.SetMapIndex(key, v)
		} else if ref.PrimaryValue != "" {
			mapv.SetMapIndex(key, reflect.ValueOf(ref.PrimaryValue))
		}
	}
	association.Error = association.DB.Session(&Session{
		NewDB: true,
	}).Model(child.Interface()).Create(mapv.Interface()).Error
case schema.Many2Many:
	association.Error = association.DB.Session(&Session{
		NewDB: true,
	}).Model(child.Interface()).Create(mapv.Interface()).Error

	for _, key := range mapv.MapKeys() {
		k := strings.ToLower(key.String())
		if f, ok := association.Relationship.FieldSchema.FieldsByDBName[k]; ok {
			_ = f.Set(association.DB.Statement.Context, child, mapv.MapIndex(key).Interface())
		}
	}
	appendToFieldValues(child)
}

if v, ok := selectColumns[field.DBName]; (ok && v) || (!ok && !restricted) {
	if mv, mok := stmt.Dest.(map[string]interface{}); mok {
		if fv, ok := mv[field.Name]; ok {
			return !utils.AssertEqual(fv, fieldValue)
		} else if fv, ok := mv[field.DBName]; ok {
			return !utils.AssertEqual(fv, fieldValue)
		}
	} else {
		destValue := reflect.ValueOf(stmt.Dest)
		for destValue.Kind() == reflect.Ptr {
			destValue = destValue.Elem()
		}
		if descSchema, err := schema.Parse(stmt.Dest, stmt.DB.cacheStore, stmt.DB.NamingStrategy); err == nil {
			if destField := descSchema.LookUpField(field.DBName); destField != nil {
				changedValue, zero := destField.ValueOf(stmt.Context, destValue)
				if v {
					return !utils.AssertEqual(changedValue, fieldValue)
				}
				return !zero && !utils.AssertEqual(changedValue, fieldValue)
			}
		}
	}
}

if !updatingValue.CanAddr() || stmt.Dest != stmt.Model {
	switch stmt.ReflectValue.Kind() {
	case reflect.Slice, reflect.Array:
		if size := stmt.ReflectValue.Len(); size > 0 {
			var isZero bool
			for i := 0; i < size; i++ {
				for _, field := range stmt.Schema.PrimaryFields {
					_, isZero = field.ValueOf(stmt.Context, stmt.ReflectValue.Index(i))
					if !isZero {
						break
					}
				}
			}

			if !isZero {
				_, primaryValues := schema.GetIdentityFieldValuesMap(stmt.Context, stmt.ReflectValue, stmt.Schema.PrimaryFields)
				column, values := schema.ToQueryValues("", stmt.Schema.PrimaryFieldDBNames, primaryValues)
				stmt.AddClause(clause.Where{Exprs: []clause.Expression{clause.IN{Column: column, Values: values}}})
			}
		}
	case reflect.Struct:
		for _, field := range stmt.Schema.PrimaryFields {
			if value, isZero := field.ValueOf(stmt.Context, stmt.ReflectValue); !isZero {
				stmt.AddClause(clause.Where{Exprs: []clause.Expression{clause.Eq{Column: field.DBName, Value: value}}})
			}
		}
	}
}

for idx, foreignField := range foreignFields {
	// use same data type for foreign keys
	schema.Relationships.Mux.Lock()
	if schema != foreignField.Schema {
		foreignField.Schema.Relationships.Mux.Lock()
	}
	if copyableDataType(primaryFields[idx].DataType) {
		foreignField.DataType = primaryFields[idx].DataType
	}
	foreignField.GORMDataType = primaryFields[idx].GORMDataType
	if foreignField.Size == 0 {
		foreignField.Size = primaryFields[idx].Size
	}
	schema.Relationships.Mux.Unlock()
	if schema != foreignField.Schema {
		foreignField.Schema.Relationships.Mux.Unlock()
	}

	relation.References = append(relation.References, &Reference{
		PrimaryKey:    primaryFields[idx],
		ForeignKey:    foreignField,
		OwnPrimaryKey: (schema == primarySchema && gl == guessHas) || (field.OwnerSchema == primarySchema && gl == guessEmbeddedHas),
	})
}

switch rv.Kind() {
case reflect.Slice, reflect.Array:
	if rv.Len() > 0 {
		association.Error = association.Relationship.Field.Set(association.DB.Statement.Context, source, rv.Index(0).Addr().Interface())

		if association.Relationship.Field.FieldType.Kind() == reflect.Struct {
			assignBacks = append(assignBacks, assignBack{Source: source, Dest: rv.Index(0)})
		}
	}
case reflect.Struct:
	if !rv.CanAddr() {
		association.Error = ErrInvalidValue
		return
	}
	association.Error = association.Relationship.Field.Set(association.DB.Statement.Context, source, rv.Addr().Interface())

	if association.Relationship.Field.FieldType.Kind() == reflect.Struct {
		assignBacks = append(assignBacks, assignBack{Source: source, Dest: rv})
	}
}

map[string]*regexp.Regexp{
	// for Enums(A, B)
	enumsTag: regexp.MustCompile(`(?i)\s+enums\(.*?\)(?:\s|$)`),
	// for maximum(0)
	maximumTag: regexp.MustCompile(`(?i)\s+(?:maxinum|maximum)\(.*?\)(?:\s|$)`),
	// for minimum(0)
	minimumTag: regexp.MustCompile(`(?i)\s+(?:mininum|minimum)\(.*?\)(?:\s|$)`),
	// for default(0)
	defaultTag: regexp.MustCompile(`(?i)\s+default\(.*?\)(?:\s|$)`),
	// for minlength(0)
	minLengthTag: regexp.MustCompile(`(?i)\s+minlength\(.*?\)(?:\s|$)`),
	// for maxlength(0)
	maxLengthTag: regexp.MustCompile(`(?i)\s+maxlength\(.*?\)(?:\s|$)`),
	// for format(email)
	formatTag: regexp.MustCompile(`(?i)\s+format\(.*?\)(?:\s|$)`),
	// for extensions(x-example=test)
	extensionsTag: regexp.MustCompile(`(?i)\s+extensions\(.*?\)(?:\s|$)`),
	// for collectionFormat(csv)
	collectionFormatTag: regexp.MustCompile(`(?i)\s+collectionFormat\(.*?\)(?:\s|$)`),
	// example(0)
	exampleTag: regexp.MustCompile(`(?i)\s+example\(.*?\)(?:\s|$)`),
	// schemaExample(0)
	schemaExampleTag: regexp.MustCompile(`(?i)\s+schemaExample\(.*?\)(?:\s|$)`),
}

